/**
 * Monta o HTML da proposta de seguro pronto para virar PDF.
 *
 * Bifurca por ramo (vida vs auto) lido de Carregar tarefa.custom_attributes.ramo.
 * Em vida: cobre morte, invalidez, doenças graves etc com carências.
 * Em auto: cobre compreensiva/rcf/app etc com FIPE/franquia + assistência 24h.
 */
const input = $('Gatilho').first().json;
const tarefa = $('Carregar tarefa').first().json;
const ramo = String(tarefa?.custom_attributes?.ramo ?? 'vida').toLowerCase();
const isAuto = ramo === 'auto';

let planos = input.planos;
if (typeof planos === 'string') {
  try { planos = JSON.parse(planos); } catch { throw new Error('planos deve ser JSON array.'); }
}
if (!Array.isArray(planos) || planos.length === 0) {
  throw new Error('planos obrigatório (array com as opções retornadas pela cotação).');
}

const cliente = input.cliente_nome || 'Cliente';
const disclaimer = input.disclaimer || '';
const dataEmissao = DateTime.now().setLocale('pt-BR').toFormat("dd 'de' LLLL 'de' yyyy");
const titulo = isAuto ? 'Proposta de Seguro Auto' : 'Proposta de Seguro de Vida';

function brl(v) { return (Number(v) || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }); }

function labelCobertura(tipo) {
  const map = {
    morte: 'Morte',
    invalidez_permanente_acidente: 'Invalidez por acidente',
    invalidez_permanente_doenca: 'Invalidez por doença',
    doencas_graves: 'Doenças graves',
    auxilio_funeral: 'Auxílio funeral',
    diaria_incapacidade_temporaria: 'Diária de incapacidade',
    compreensiva: 'Compreensiva (casco + RCF + APP)',
    rcf: 'Responsabilidade civil facultativa',
    app: 'Acidentes pessoais de passageiros',
    basica: 'Básica',
    rcf_materiais: 'RCF danos materiais',
    rcf_corporais: 'RCF danos corporais',
    app_acidentes_pessoais: 'APP'
  };
  return map[tipo] ?? tipo;
}

function valorCobertura(c) {
  if (c.valorFipeSimulado !== undefined) {
    return `FIPE ${brl(c.valorFipeSimulado)} · franquia ${brl(c.franquia)}`;
  }
  if (c.valorDiario !== undefined) return `${brl(c.valorDiario)}/dia`;
  if (c.capital !== undefined) return brl(c.capital);
  return '—';
}

function coberturasHtml(coberturas) {
  return coberturas.map(c =>
    `<tr><td class="cov-nome">${labelCobertura(c.tipo)}</td><td class="cov-val">${valorCobertura(c)}</td></tr>`
  ).join('');
}

function rodapeHtml(p) {
  if (isAuto) {
    const assist = (p.assistencia24h ?? []).join(', ');
    return assist
      ? `<div class="carencias"><strong>Assistência 24h:</strong> ${assist}</div>`
      : '';
  }
  const c = p.carencias ?? {};
  if (!c.morteNatural && !c.morteAcidental && !c.invalidezAcidente) return '';
  return `<div class="carencias">
      <strong>Carências:</strong>
      morte natural ${c.morteNatural ?? '—'} · morte acidental ${c.morteAcidental ?? '—'} ·
      invalidez acidente ${c.invalidezAcidente ?? '—'}
    </div>`;
}

const planosHtml = planos.map((p, i) => `
  <div class="plano">
    <div class="plano-head">
      <div>
        <div class="plano-nome">Opção ${i + 1}: ${p.produto.nome}</div>
        <div class="plano-op">${p.operadora.nome} · SUSEP ${p.operadora.registroSusep}</div>
      </div>
      <div class="preco">
        <div class="preco-valor">${brl(p.premio.mensal)}<span class="preco-unit">/mês</span></div>
        <div class="preco-anual">${brl(p.premio.anual)} por ano</div>
      </div>
    </div>
    <table class="cov-table">
      <tr><th colspan="2">Coberturas</th></tr>
      ${coberturasHtml(p.coberturas)}
    </table>
    ${rodapeHtml(p)}
  </div>
`).join('');

const html = `<!DOCTYPE html>
<html lang="pt-BR"><head><meta charset="UTF-8"><title>Proposta</title>
<style>
  * { box-sizing: border-box; }
  body { font-family: -apple-system, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; margin: 0; padding: 30px 36px; color: #1f2937; font-size: 11pt; line-height: 1.4; }
  .header { display: flex; justify-content: space-between; align-items: flex-end; border-bottom: 3px solid #1e3a8a; padding-bottom: 10pt; margin-bottom: 18pt; }
  .title { color: #1e3a8a; font-size: 20pt; font-weight: 700; margin: 0; }
  .subtitle { color: #6b7280; font-size: 9pt; margin-top: 2pt; }
  .brand { text-align: right; }
  .brand-name { font-weight: 700; font-size: 12pt; color: #1e3a8a; }
  .brand-sub { color: #6b7280; font-size: 9pt; }
  .plano { border: 1px solid #e5e7eb; border-radius: 8pt; padding: 12pt 14pt; margin-bottom: 10pt; page-break-inside: avoid; }
  .plano-head { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 8pt; }
  .plano-nome { color: #1e3a8a; font-size: 12pt; font-weight: 700; }
  .plano-op { color: #6b7280; font-size: 9pt; margin-top: 1pt; }
  .preco { text-align: right; }
  .preco-valor { font-size: 16pt; color: #047857; font-weight: 700; }
  .preco-unit { font-size: 10pt; font-weight: 400; color: #6b7280; }
  .preco-anual { color: #6b7280; font-size: 9pt; margin-top: 1pt; }
  .cov-table { width: 100%; border-collapse: collapse; margin-top: 4pt; }
  .cov-table th { text-align: left; color: #374151; font-size: 9pt; padding: 4pt 0 2pt 0; border-bottom: 1px solid #e5e7eb; }
  .cov-table td { font-size: 9.5pt; padding: 3pt 0; }
  .cov-nome { color: #4b5563; width: 60%; }
  .cov-val { color: #111827; font-weight: 500; text-align: right; }
  .carencias { margin-top: 8pt; font-size: 8.5pt; color: #6b7280; border-top: 1px dashed #e5e7eb; padding-top: 6pt; }
  .disclaimer { margin-top: 16pt; padding-top: 10pt; border-top: 1px solid #e5e7eb; font-size: 8pt; color: #9ca3af; font-style: italic; }
</style></head><body>
  <div class="header">
    <div>
      <h1 class="title">${titulo}</h1>
      <div class="subtitle">Emitida em ${dataEmissao}</div>
    </div>
    <div class="brand">
      <div class="brand-name">Moreira Seguros</div>
      <div class="brand-sub">Cliente: ${cliente}</div>
    </div>
  </div>
  ${planosHtml}
  ${disclaimer ? `<div class="disclaimer">${disclaimer}</div>` : ''}
</body></html>`;

const safeCli = (cliente.replace(/[^a-z0-9]/gi, '-').toLowerCase() || 'cliente');
const filename = `proposta-${ramo}-${safeCli}-${DateTime.now().toFormat('yyyy-MM-dd')}.pdf`;

return [{ json: { html, filename, ramo } }];

/**
 * Renomeia o binary para o nome do arquivo e devolve junto
 * o texto de abertura que vai acompanhar o PDF.
 */
const filename = $('Montar HTML').first().json.filename;
const input = $('Gatilho').first().json;

const mensagem = (input.mensagem_abertura ||
  '📋 Segue sua proposta personalizada em PDF, com as 3 opções comparadas lado a lado. Me diga qual opção fez mais sentido e a gente segue com a contratação.'
);

// Ajusta o filename no binary
const binary = $input.first().binary ?? {};
if (binary.data) {
  binary.data.fileName = filename;
  binary.data.mimeType = 'application/pdf';
}

return [{
  json: { mensagem, filename },
  binary
}];
